const inputItem = $input.first();

if (!inputItem) {
  throw new Error('No input item found');
}

const children = Array.isArray(inputItem.json.value) ? inputItem.json.value : [];

// Clinic folders only
const clinicFolders = children.filter(item => item.folder);

// Lock files only
const lockFiles = children.filter(item => {
  const name = item.name || '';
  return !item.folder && name.toUpperCase().startsWith('_AUMEDORDER_COMPLETE_');
});

const clinicResults = clinicFolders.map(folder => {
  const clinic = folder.name;
  const expectedLockFileName = `_AuMedOrder_COMPLETE_${clinic}.txt`;

  const matchingLockFile = lockFiles.find(file =>
    (file.name || '').toUpperCase() === expectedLockFileName.toUpperCase()
  );

  const hasLockFile = !!matchingLockFile;

  return {
    clinic,
    clinicFolderId: folder.id,
    clinicChildCount: folder.folder?.childCount ?? 0,

    expectedLockFileName,
    hasLockFile,

    lockFileId: matchingLockFile?.id || null,
    lockFileName: matchingLockFile?.name || null,

    // Useful for future routing
    route: hasLockFile ? 'complete' : 'incomplete',
  };
});

const completedClinics = clinicResults.filter(row => row.hasLockFile);
const incompleteClinics = clinicResults.filter(row => !row.hasLockFile);

const allClinicsComplete =
  clinicFolders.length > 0 &&
  incompleteClinics.length === 0;

return [
  {
    json: {
      totalClinicFolders: clinicFolders.length,
      totalLockFiles: lockFiles.length,

      completedClinicCount: completedClinics.length,
      incompleteClinicCount: incompleteClinics.length,

      allClinicsComplete,
      shouldArchive: allClinicsComplete,
      shouldRedirectIncomplete: !allClinicsComplete,

      completedClinics,
      incompleteClinics,

      completedClinicNames: completedClinics.map(row => row.clinic),
      incompleteClinicNames: incompleteClinics.map(row => row.clinic),

      clinicResults,
    },
  },
];

